import { TEXT_ELEMENT } from '../core/element-constants';
import { MIDDLE_ALIGN, END_ALIGN, BOTTOM_ALIGN } from '../core/align-constants';
import { NULL } from '../core/zc-constants';
import { d3_select } from '../core/d3-constants';
import { getSvgTransform } from '../utils/svg-transforms';
import { handleOverflowTicks } from '../axis/ticklabel-overflow';

export function PolarTickHandler(wrap, available, config, chartObj, scaleObj, axisComponent) {
    let overflow = config.textOverflow || 'ellipsis',
        _className = 'ticklabel',
        trimmed = false,
        edge = (node, textBound) => {
            let anchor = d3_select(node).attr('text-anchor'),
                gTransform = getSvgTransform(node.parentNode),
                gTranslate = gTransform.translate,
                textTransform = getSvgTransform(node),
                textTranslate = textTransform.translate,
                obj = {};

            if (anchor === MIDDLE_ALIGN) {
                let mid = (textBound.left + textBound.right) / 2;
                obj.left = mid - available;
                obj.right = mid + available;
            } else if (anchor === END_ALIGN) {
                obj.right = textBound.left + textBound.width;
                obj.left = obj.right - gTranslate[0] - textTranslate[0] - available;
            } else {
                obj.left = textBound.left;
                obj.right = obj.left - gTranslate[0] - textTranslate[0] + available;
            }

            trimmed = trimmed || (textBound.left < obj.left || textBound.right > obj.right); // TODO: enhance

            return obj;
        },
        options = { edge, type: 'polar' },
        args = [NULL, BOTTOM_ALIGN, chartObj, 0, overflow, scaleObj, wrap, axisComponent, _className, config, 0, options],
        overflowHandler = handleOverflowTicks(...args);

    return function() {
        let tickLabels = wrap.selectAll(`${TEXT_ELEMENT}.${_className}`);

        tickLabels.each(function(d, i) {
            overflowHandler(this, i);
        });

        chartObj.cache.polarAxis = { trimmed }; // TODO: enhance
    };
}
